+    #[test]
+    fn polar_identity() {
+        let a = [1.0, 0.0, 0.0, 1.0];
+        let (u, p) = polar_nxn(&a, 2).unwrap();
+        // Identity: U = I, P = I
+        for i in 0..2 {
+            for j in 0..2 {
+                let expected = if i == j { 1.0 } else { 0.0 };
+                assert!(
+                    (u[i * 2 + j] - expected).abs() < 1e-10,
+                    "polar U identity [{i},{j}]"
+                );
+                assert!(
+                    (p[i * 2 + j] - expected).abs() < 1e-10,
+                    "polar P identity [{i},{j}]"
+                );
+            }
+        }
+    }
