+        let byte_refs: Vec<&[u8]> = encoded.iter().map(|b| b.as_slice()).collect();
+        let decoded = StringArray::decode(vec![2], &byte_refs).unwrap();
+        assert_eq!(decoded.values(), sa.values());
+    }
